head.script:
/*
    물류/공통(통합)/매입요율/운송/다착지요율관리

    조회조건
    거래처  : 311641                            
    계약번호: C2004001900

 */

scwin.MSG_LO_CRM_001 = "변경 사항이 존재합니다. 진행하시겠습니까?";

scwin.onpageload = function() {
    var codeOptions = [
        { grpCd : "SD113", compID : "gr_basetrfList:odrKndCd" }, 
        { grpCd : "OP253", compID : "gr_basetrfList:trfClsCd" }
    ];

    $c.data.setCommonCode(codeOptions, function() {
        dlt_commonCodeSD113.insertRow(0);
        dlt_commonCodeSD113.setCellData(0, "cd", "99");
        dlt_commonCodeSD113.setCellData(0, "cdNm", "전체");
    });	

    /*오더종류 setting*/
    // let param = "SD113";
    // sbm_odrKnd.action = "/cm.zz.RetrieveComboCMD.do?sysCd=CommonEBC&queryId=retrieveSysCdTest_eqCode&param1=" + param;
    // $c.sbm.execute(sbm_odrKnd);

    ds_ctrtNo.removeAll();

    var codeOptions1 = [
        {
            method: "getGridCombo",
            param1: "EquipmentEBC",
            param2: "retrieveLogisticsEquipmentClss",
            param3: ["ZZ210","ZZ202","ZZ201","LV"],
            param4: true,
            compID: "gr_basetrfList:vehclKndCd"
        }
    ];

    $c.data.setGauceUtil(codeOptions1, function() {
        dlt_gauceUtil_gr_basetrfList_vehclKndCd.insertRow(0);
        dlt_gauceUtil_gr_basetrfList_vehclKndCd.setCellData(0, "code", "99");
        dlt_gauceUtil_gr_basetrfList_vehclKndCd.setCellData(0, "name", "전체");
    });

    $c.sbm.execute(sbm_eqNrmCd);

};

scwin.onUdcCompleted = function() {
    scwin.f_defaultValue();
    ed_clntNo.focus();
};

//-------------------------------------------------------------------------
// function name : scwin.f_defaultValue
// function desc : 화면 open시 초기 데이타 setting
//-------------------------------------------------------------------------
scwin.f_defaultValue = function() {
    ed_clntNo.focus();
    ds_ctrtNo.removeAll();
};


//-------------------------------------------------------------------------
// function name : scwin.f_Addrow
// function desc : 행추가
//-------------------------------------------------------------------------
scwin.f_addrow = async function() {
    //거래처
    if (!await $c.gus.cfValidate([ed_clntNo])) {
        return;
    }

    //계약번호
    if (await $c.gus.cfValidate([lc_ctrtNo])) {
        if (lc_ctrtNo.getValue() == "선택") {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["계약번호"]);//"@을(를) 선택하십시오.";
            return;
        }
    } else {
        return;
    }

    var nRow = ds_basetrfList.getRowCount();
    var rowIdx = ds_basetrfList.getRowPosition();
    if (rowIdx == null) {
        gr_basetrfList.setFocusedCell(nRow - 1, 0);
        return;
    }

    if (nRow == 0) {
        ds_basetrfList.insertRow(nRow);
        ds_basetrfList.setCellData(ds_basetrfList.getRowPosition() || 0, "ctrtNo", lc_ctrtNo.getValue());
        gr_basetrfList.setFocusedCell(nRow, "adptDt");

    } else {
        $c.gus.cfCopyRecord(gr_basetrfList);
        gr_basetrfList.setFocusedCell(nRow, "adptDt");
    }

};


//-------------------------------------------------------------------------
// function name : f_Delrow
// function desc : 행삭제
//-------------------------------------------------------------------------
scwin.f_delrow = function() {
    var rowIdx = ds_basetrfList.getRowPosition();
    if (rowIdx == null) {
        return;
    }

    if (ds_basetrfList.getRowStatus(rowIdx) == "C") {
        ds_basetrfList.removeRow(rowIdx);
    } else {
        ds_basetrfList.deleteRow(rowIdx);
    }
    gr_basetrfList.removeFocusedCell();
};


//-------------------------------------------------------------------------
// function name : f_undo
// function desc : 취소
//-------------------------------------------------------------------------
scwin.f_undo = function() {
	$c.data.undoRow(ds_basetrfList);
    ds_basetrfList.setRowPosition(ds_basetrfList.getTotalRow() - 1);
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    if (!await scwin.f_validChk()) {
        return
    }

    ds_basetrfList.removeAll();
    dma_retrieve.setEmptyValue();
    dma_retrieve.set("ctrtNo", lc_ctrtNo.getValue())  //계약번호

    $c.sbm.execute(sbm_retrieve);
};


//-------------------------------------------------------------------------
// function name : scwin.f_validChk
// function desc : 필수 조회 조건 check
//-------------------------------------------------------------------------
scwin.f_validChk = async function() {
    if (ds_basetrfList.getModifiedIndex().length != 0) {
        if (!await $c.win.confirm(scwin.MSG_LO_CRM_001)) {
            return false;
        }
    }

    //거래처
    if (!await $c.gus.cfValidate([ed_clntNo])) {
        return false;
    }

    //계약번호
    if (await $c.gus.cfValidate([lc_ctrtNo])) {
        if (lc_ctrtNo.getValue() == "선택") {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["계약번호"]);//"@을(를) 선택하십시오.";
            return false;
        }
    } else {
        return false;
    }

    return true;
};


//-------------------------------------------------------------------------
// function name : scwin.f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    var chk = await scwin.f_ReqFieldChk();
    if (chk == true) {
        if (await $c.win.confirm(MSG_CM_CRM_001)) {
            $c.sbm.execute(sbm_save);
        }
    }
};


//-------------------------------------------------------------------------
// function name : scwin.f_ReqFieldChk
// function desc : 필수 입력항목 체크
//-------------------------------------------------------------------------
scwin.f_ReqFieldChk = async function() {

    if (ds_basetrfList.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["다착지 요율"]);//"@은(는) 변경된 사항이 없습니다.";
        return false;
    }

    //거래처
    if (!await $c.gus.cfValidate([ed_clntNo])) {
        return;
    }

    //계약번호
    if (await $c.gus.cfValidate([lc_ctrtNo])) {
        if (lc_ctrtNo.getValue(0) == "선택") {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["계약번호"]);//"@을(를) 선택하십시오.";
            return;
        }
    } else {
        return;
    }

    let validArray = [
        {id:"adptDt", name: "적용일자", mandatory: true},
        {id:"wrkPlCd", name: "작업장코드", mandatory: true},
        {id:"wrkPlNm", name: "작업장명", mandatory: true},
        {id:"odrKndCd", name: "오더종류", mandatory: true},
        {id:"vehclKndCd", name: "차량종류", mandatory: true},
        {id:"vehclNrmCd", name: "차량규격", mandatory: true},
        {id:"trfClsCd", name: "요율구분", mandatory: true},
        {id:"pchsAmt", name: "매입금액", mandatory: true},
        {id:"sellAmt", name: "매출금액", mandatory: true},
    ]
    var ret = await $c.gus.cfValidateGrid(gr_basetrfList, null, null, validArray, "다착지 요율 관리");

    if (!ret) {
        return false;
    }

    return true;
};


//-------------------------------------------------------------------------
// List 엑셀파일로 저장
//-------------------------------------------------------------------------
scwin.f_toExcel1 = async function() {
    var fileName = "다착지요율관리";
    await $c.data.downloadGridViewExcel(gr_basetrfList, { fileName: fileName + ".xlsx", sheetName: fileName });
};


//-------------------------------------------------------------------------
// 조회조건 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, null);
    scwin.f_defaultValue();
};


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    udc_comCodClntNo.cfCommonPopUp(scwin.udc_comCodClntNo_callBackFunc	    // XML상의 SELECT ID	
					        ,pCode					// 화면에서의 ??? Code Element의	Value
					        ,pName					// 화면에서의 ??? Name Element의	Value
					        ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
					        ,'5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
					        ,null					// Title순서	
					        ,'150,170'  		    // 보여주는 각 컬럼들의 폭	
					        ,'3,4,5,6,7,8,9,10'		// 컬럼중에서 숨기는	컬럼 지정	
					        ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
					        ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
					        ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
					        ,null					// 윈도우 위치 Y좌표	
					        ,null					// 윈도우 위치 X좌표
					        ,null					// 중복체크여부	("F")
					        ,pAllSearch				// 전체검색허용여부	("F")
					        ,'거래처 조회,거래처코드 ,거래처명 '				    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
					       );								
};

scwin.udc_comCodClntNo_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_clntNo, txt_clntNm);
    ds_retrieveCtrtClnt.set("ctrtClntNo", ed_clntNo.getValue());
    $c.sbm.execute(sbm_retrieveCtrtClnt);
};


//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
 	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj))
       return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

   	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};


//-------------------------------------------------------------------------
// 그리드에서 팝업조회
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = function(row, pColid, pClose) {
    var pCode = "";
    var pName = "";
    var pAllSearch = 'F';

    switch (pColid) {

        //작업장코드
	    case "wrkPlCd":
	        pCode = ds_basetrfList.getCellData(row, "wrkPlCd");
  		    udc_comCodeGrid.cfCommonPopUp(function(rtnList) {
                                        $c.gus.cfSetGridReturnValue(rtnList, ds_basetrfList, row, "wrkPlCd", "wrkPlNm");
                                    }	    // XML상의 SELECT ID	
							        ,pCode					// 화면에서의 ??? Code Element의	Value
							        ,pName					// 화면에서의 ??? Name Element의	Value
							        ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
							        ,'5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
							        ,null					// Title순서	
							        ,'150,170'  		    // 보여주는 각 컬럼들의 폭	
							        ,'3,4,5,6,7,8,9,10'		// 컬럼중에서 숨기는	컬럼 지정	
							        ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
							        ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
							        ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
							        ,null					// 윈도우 위치 Y좌표	
							        ,null					// 윈도우 위치 X좌표
							        ,null					// 중복체크여부	("F")
							        ,pAllSearch				// 전체검색허용여부	("F")
							        ,'작업장 조회,작업장코드 ,작업장명 '				    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
							       );								
		    break;

        //작업장명
	    case "wrkPlNm":
	        pName = ds_basetrfList.getCellData(row, "wrkPlNm");
  		    udc_comCodeGrid.cfCommonPopUp(function(rtnList) {
                                        $c.gus.cfSetGridReturnValue(rtnList, ds_basetrfList, row, "wrkPlCd", "wrkPlNm");                       
                                    }	    // XML상의 SELECT ID	
							        ,pCode					// 화면에서의 ??? Code Element의	Value
							        ,pName					// 화면에서의 ??? Name Element의	Value
							        ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
							        ,'5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
							        ,null					// Title순서	
							        ,'150,170'  		    // 보여주는 각 컬럼들의 폭	
							        ,'3,4,5,6,7,8,9,10'		// 컬럼중에서 숨기는	컬럼 지정	
							        ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
							        ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
							        ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
							        ,null					// 윈도우 위치 Y좌표	
							        ,null					// 윈도우 위치 X좌표
							        ,null					// 중복체크여부	("F")
							        ,pAllSearch				// 전체검색허용여부	("F")
							        ,'작업장 조회,작업장코드 ,작업장명 '				    // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
							       );								
		    break;		    	

		default:
  			break;
	}
};



// <!-----------------------------------------------------------------------------
//     G A U C E   C O M P O N E N T' S   E V E N T S  
// ------------------------------------------------------------------------------>

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;	// OnFail

    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    ds_basetrfList.modifyAllStatus("R");

    await scwin.f_Retrieve();
};


scwin.sbm_retrieveCtrtClnt_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;	// OnFail

	if (ds_ctrtNo.getRowCount() == 0 ){
		await $c.gus.cfAlertMsg("거래처 %2의 " + MSG_CM_ERR_049, ["계약번호", txt_clntNm.getValue()]);

    } else {
        //sort - <param name=SortExpr value="-ctrtNo">
        ds_ctrtNo.sort("ctrtNo", 1);
    }

	//ds_EqNrmCd.UseFilter = true;
};


scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;	// OnFail

    // for=ds_basetrfList event=OnLoadCompleted(rowcnt)
    totalRows.setValue(ds_basetrfList.getRowCount());

    if (ds_basetrfList.getRowCount() == 0 ){
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002); //조회결과가 존재하지 않습니다.
    }	

    for (var i = 0; i < ds_basetrfList.getRowCount(); i++) {
        let odrKndCd = ds_basetrfList.getCellData(i, "odrKndCd");
        if (odrKndCd == "") {
            ds_basetrfList.setCellData(i, "odrKndCd", "99");
        }
    }

    gr_basetrfList.setFocusedCell(0, 0);
    $c.sbm.execute(sbm_eqNrmCd);
};



// 거래처 udc 이벤트
scwin.udc_comCodClntNo_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_clntNo, txt_clntNm, 1); 
};

scwin.udc_comCodClntNo_onviewchangeNameEvent = function (info) {
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), txt_clntNm.getValue(), 'F', 'T');
};

scwin.udc_comCodeGrid_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_clntNo.getValue(), txt_clntNm.value.getValue(), 'F', 'T');
};


scwin.udc_comCodeGrid_callBackFunc = function (ret) {

    let rowIdx = gr_basetrfList.getFocusedRowIndex();
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ds_basetrfList.setCellData(rowIdx, "wrkPlCd", ret[0]); //품명코드
        ds_basetrfList.setCellData(rowIdx, "wrkPlNm", ret[1]); //품명
    }

    $c.sbm.execute(sbm_retrieveCtrtClnt);
};


scwin.sbm_eqNrmCd_submitdone = function (e) {
    ds_EqNrmCd.insertRow(0);
    ds_EqNrmCd.setCellData(0, "upperCd", "99");
	ds_EqNrmCd.setCellData(0, "cd", "00");
	ds_EqNrmCd.setCellData(0, "cdNm", "전체");
    $c.gus.cfChangeCdNmFormat(ds_EqNrmCd, "cd", "cdNm");
};

