scwin.gr_basetrfList_ontextimageclick = function (rowIndex, columnIndex) {

    var colId = gr_basetrfList.getColumnID(columnIndex);
	switch (colId) {
		case "clntNm":
			scwin.f_openCommPopUpGrid(rowIndex, "wrkPlCd", 'F');
			break;	

		case "wrkPlNm":
			scwin.f_openCommPopUpGrid(rowIndex, "wrkPlNm", 'F');
			break;

		case "adptDt":
			//cfOpenCalendar(gr_basetrfList, row, colid);
			break;			
	}		
};


scwin.gr_basetrfList_onbeforeedit = function (rowIndex, columnIndex, value) {
    scwin.gr_oldData = null;
    var colId = gr_basetrfList.getFocusedColumnID();
    if (colId == "wrkPlCd" || colId == "wrkPlNm") {
        scwin.gr_oldData = value;
    }
};

scwin.gr_basetrfList_onafteredit = function (rowIndex, columnIndex, value) {
    var colId = gr_basetrfList.getFocusedColumnID();

    switch (colId) {
        case "wrkPlCd":     // 작업장코드
            if (value != "" && value != scwin.gr_oldData){
                ds_basetrfList.setCellData(rowIndex, "wrkPlNm", "");
                scwin.f_openCommPopUpGrid(rowIndex, "wrkPlCd", 'T');

            } else if (value == "") {
                ds_basetrfList.setCellData(rowIndex, "wrkPlCd", "");
                ds_basetrfList.setCellData(rowIndex, "wrkPlNm", "");
            }
            break;	

        case "wrkPlNm":     // 작업장명
            if (value != "" && value != scwin.gr_oldData){
                ds_basetrfList.setCellData(rowIndex, "wrkPlCd", "");
                scwin.f_openCommPopUpGrid(rowIndex,  "wrkPlNm", 'T');

            } else if (value == "") {
                ds_basetrfList.setCellData(rowIndex, "wrkPlCd", "");
                ds_basetrfList.setCellData(rowIndex, "wrkPlNm", "");
            }
            break;	

        case "vehclKndCd":  // 차량종류 - 선택 시 차량규격(vehclNrmCd) 콤보 fliter
            // scwin.ds_EqNrmCd_OnFilter();
            gr_basetrfList.refreshColumn("vehclNrmCd");
            break;
    }
};


scwin.ds_basetrfList_onrowpositionchange = function (info) {
	if (ds_basetrfList.getRowStatus(info.newRowIndex) != "R" ) {
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "adptDt", false);
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "wrkPlCd", false);
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "wrkPlNm", false);
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "odrKndCd", false);
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "vehclKndCd", false);
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "vehclNrmCd", false);
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "trfClsCd", false);
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "pchsAmt", false);
        gr_basetrfList.setCellReadOnly(info.newRowIndex, "sellAmt", false);

	}
    scwin.ds_EqNrmCd_OnFilter();

    //$c.gus.cfPrepareHidVal(ds_basetrfList, info.newRowIndex, ["clntCd", "clntNm","wrkPlCd", "wrkPlNm"]);
};
